#include<bits/stdc++.h>
using namespace std;
int sum[500010],n,m,a[500010];
int lowbit(int x)
{
    return x&-x;
}
void add(int x,int v)
{
    for(int i=x;i<=n+1;i+=lowbit(i))
    {
        sum[i]+=v;
    }
}
int query(int x)
{
    int ans=0;
    for(int i=x;i>=1;i-=lowbit(i))
    {
        ans+=sum[i];
    }
    return ans;
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        add(i,a[i]-a[i-1]);
    }
    while(m--)
    {
        int op,x,y,k;
        scanf("%d%d",&op,&x);
        if(op==1)
        {
            scanf("%d%d",&y,&k);
            add(x,k);
            add(y+1,-k);
        }
        else
        {
            printf("%d\n",query(x));
        }
    }
    return 0;
}
